import{_ as i,o,c as a,ag as l}from"./chunks/framework.CTpQozEL.js";const m=JSON.parse('{"title":"메뉴 바","description":"메뉴 바 상태 로직 및 사용자에게 표시되는 내용","frontmatter":{"title":"메뉴 바","description":"메뉴 바 상태 로직 및 사용자에게 표시되는 내용"},"headers":[],"relativePath":"platforms/mac/menu-bar.md","filePath":"platforms/mac/menu-bar.md","lastUpdated":null}'),t={name:"platforms/mac/menu-bar.md"};function d(c,e,r,n,u,s){return o(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="메뉴-바-상태-로직" tabindex="-1">메뉴 바 상태 로직 <a class="header-anchor" href="#메뉴-바-상태-로직" aria-label="Permalink to &quot;메뉴 바 상태 로직&quot;">​</a></h1><h2 id="표시되는-내용" tabindex="-1">표시되는 내용 <a class="header-anchor" href="#표시되는-내용" aria-label="Permalink to &quot;표시되는 내용&quot;">​</a></h2><ul><li>메뉴 바 아이콘과 메뉴의 첫 번째 상태 행에 현재 에이전트 작업 상태를 표시합니다.</li><li>작업이 활성 상태인 동안 상태 표시는 숨겨집니다. 모든 세션이 유휴 상태가 되면 돌아옵니다.</li><li>메뉴의 &quot;Nodes&quot; 블록은 <code>node.list</code>를 통한 페어링된 노드인 <strong>기기</strong>만 나열합니다. 클라이언트/프레전스 항목은 제외됩니다.</li><li>공급자 사용 스냅샷이 사용 가능한 경우 Context 아래에 &quot;Usage&quot; 섹션이 나타납니다.</li></ul><h2 id="상태-모델" tabindex="-1">상태 모델 <a class="header-anchor" href="#상태-모델" aria-label="Permalink to &quot;상태 모델&quot;">​</a></h2><ul><li>세션: 이벤트는 <code>runId</code> (실행당) 및 페이로드의 <code>sessionKey</code>와 함께 도착합니다. &quot;main&quot; 세션은 키 <code>main</code>입니다. 없으면 가장 최근에 업데이트된 세션으로 대체됩니다.</li><li>우선순위: main이 항상 우선합니다. main이 활성 상태이면 상태가 즉시 표시됩니다. main이 유휴 상태이면 가장 최근에 활성 상태였던 main이 아닌 세션이 표시됩니다. 활동 중간에 전환하지 않습니다. 현재 세션이 유휴 상태가 되거나 main이 활성화될 때만 전환합니다.</li><li>활동 종류: <ul><li><code>job</code>: 고수준 명령 실행 (<code>state: started|streaming|done|error</code>).</li><li><code>tool</code>: <code>toolName</code> 및 <code>meta/args</code>와 함께 <code>phase: start|result</code>.</li></ul></li></ul><h2 id="iconstate-열거형-swift" tabindex="-1">IconState 열거형 (Swift) <a class="header-anchor" href="#iconstate-열거형-swift" aria-label="Permalink to &quot;IconState 열거형 (Swift)&quot;">​</a></h2><ul><li><code>idle</code></li><li><code>workingMain(ActivityKind)</code></li><li><code>workingOther(ActivityKind)</code></li><li><code>overridden(ActivityKind)</code> (디버그 재정의)</li></ul><h3 id="activitykind-→-글리프" tabindex="-1">ActivityKind → 글리프 <a class="header-anchor" href="#activitykind-→-글리프" aria-label="Permalink to &quot;ActivityKind → 글리프&quot;">​</a></h3><ul><li><code>exec</code> → 💻</li><li><code>read</code> → 📄</li><li><code>write</code> → ✍️</li><li><code>edit</code> → 📝</li><li><code>attach</code> → 📎</li><li>기본값 → 🛠️</li></ul><h3 id="시각적-매핑" tabindex="-1">시각적 매핑 <a class="header-anchor" href="#시각적-매핑" aria-label="Permalink to &quot;시각적 매핑&quot;">​</a></h3><ul><li><code>idle</code>: 일반 크리터.</li><li><code>workingMain</code>: 글리프가 있는 배지, 전체 색조, 다리 &quot;작업 중&quot; 애니메이션.</li><li><code>workingOther</code>: 글리프가 있는 배지, 음소거된 색조, 스커리 없음.</li><li><code>overridden</code>: 활동에 관계없이 선택한 글리프/색조를 사용합니다.</li></ul><h2 id="상태-행-텍스트-메뉴" tabindex="-1">상태 행 텍스트 (메뉴) <a class="header-anchor" href="#상태-행-텍스트-메뉴" aria-label="Permalink to &quot;상태 행 텍스트 (메뉴)&quot;">​</a></h2><ul><li>작업이 활성 상태인 동안: <code>&amp;lt;Session role&amp;gt; · &amp;lt;activity label&amp;gt;</code><ul><li>예시: <code>Main · exec: pnpm test</code>, <code>Other · read: apps/macos/Sources/OpenClaw/AppState.swift</code>.</li></ul></li><li>유휴 상태일 때: 상태 요약으로 대체됩니다.</li></ul><h2 id="이벤트-수집" tabindex="-1">이벤트 수집 <a class="header-anchor" href="#이벤트-수집" aria-label="Permalink to &quot;이벤트 수집&quot;">​</a></h2><ul><li>소스: 제어 채널 <code>agent</code> 이벤트 (<code>ControlChannel.handleAgentEvent</code>).</li><li>파싱된 필드: <ul><li>시작/중지를 위한 <code>data.state</code>와 함께 <code>stream: &quot;job&quot;</code>.</li><li><code>data.phase</code>, <code>name</code>, 선택적 <code>meta</code>/<code>args</code>와 함께 <code>stream: &quot;tool&quot;</code>.</li></ul></li><li>레이블: <ul><li><code>exec</code>: <code>args.command</code>의 첫 번째 줄.</li><li><code>read</code>/<code>write</code>: 축약된 경로.</li><li><code>edit</code>: <code>meta</code>/diff 수에서 추론된 변경 종류와 함께 경로.</li><li>대체: 도구 이름.</li></ul></li></ul><h2 id="디버그-재정의" tabindex="-1">디버그 재정의 <a class="header-anchor" href="#디버그-재정의" aria-label="Permalink to &quot;디버그 재정의&quot;">​</a></h2><ul><li>설정 ▸ Debug ▸ &quot;Icon override&quot; 선택기: <ul><li><code>System (auto)</code> (기본값)</li><li><code>Working: main</code> (도구 종류별)</li><li><code>Working: other</code> (도구 종류별)</li><li><code>Idle</code></li></ul></li><li><code>@AppStorage(&quot;iconOverride&quot;)</code>를 통해 저장됨; <code>IconState.overridden</code>에 매핑됨.</li></ul><h2 id="테스트-체크리스트" tabindex="-1">테스트 체크리스트 <a class="header-anchor" href="#테스트-체크리스트" aria-label="Permalink to &quot;테스트 체크리스트&quot;">​</a></h2><ul><li>main 세션 작업 트리거: 아이콘이 즉시 전환되고 상태 행에 main 레이블이 표시되는지 확인.</li><li>main이 유휴 상태인 동안 main이 아닌 세션 작업 트리거: 아이콘/상태가 main이 아닌 것을 표시하고 완료될 때까지 안정적으로 유지.</li><li>다른 세션이 활성 상태인 동안 main 시작: 아이콘이 즉시 main으로 전환.</li><li>빠른 도구 버스트: 배지가 깜빡이지 않는지 확인 (도구 결과에 TTL 유예 적용).</li><li>모든 세션이 유휴 상태가 되면 상태 행이 다시 나타납니다.</li></ul>',19)])])}const q=i(t,[["render",d]]);export{m as __pageData,q as default};
